fn is_private_ip(ip: IpAddr) -> bool {
    match ip {
        IpAddr::V4(ipv4) => {
            ipv4.is_private()
                || ipv4.is_loopback()
                || ipv4.is_link_local()
                || ipv4.is_broadcast()
                || ipv4.is_documentation()
                || ipv4.is_unspecified()
                || ipv4.octets()[0] == 169 && ipv4.octets()[1] == 254
                || ipv4.octets()[0] == 100
                    && ipv4.octets()[1] >= 64
                    && ipv4.octets()[1] <= 127
        }
        IpAddr::V6(ipv6) => {
            ipv6.is_loopback()
                || ipv6.is_unspecified()
                || ((ipv6.segments()[0] & 0xfe00) == 0xfc00)
                || ((ipv6.segments()[0] & 0xffc0) == 0xfe80)
                || ipv6.segments()[0] == 0x2001 && ipv6.segments()[1] == 0xdb8
        }
    }
}

fn validate_url(url_str: &str) -> Result<Url, String> {
    let url = Url::parse(url_str).map_err(|_| "Invalid URL format")?;

    let scheme = url.scheme();
    if scheme != "http" && scheme != "https" {
        return Err("Only HTTP and HTTPS schemes are allowed".to_string());
    }

    let host = url.host_str().ok_or("URL must have a host")?;

    if host == "localhost"
        || host.ends_with(".local")
        || host.ends_with(".localhost")
        || host == "0.0.0.0"
        || host == "[::]"
    {
        return Err("Access to localhost is not allowed".to_string());
    }

    if let Ok(ip) = host.parse::<IpAddr>() {
        if is_private_ip(ip) {
            return Err("Access to private IP addresses is not allowed".to_string());
        }
    }

    let allowed_domains = vec!["api.example.com", "partner.example.org"];

    let is_allowed = allowed_domains.iter().any(|&domain| {
        host == domain || host.ends_with(&format!(".{}", domain))
    });

    if !is_allowed {
        return Err("URL domain is not in the allowlist".to_string());
    }

    Ok(url)
}

async fn proxy_handler(Query(params): Query<ProxyParams>) -> Response {
    let url = match validate_url(&params.url) {
        Ok(u) => u,
        Err(e) => {
            return (StatusCode::BAD_REQUEST, format!("Invalid URL: {}", e)).into_response()
        }
    };

    let client = match reqwest::Client::builder()
        .redirect(Policy::none())
        .timeout(Duration::from_secs(10))
        .connect_timeout(Duration::from_secs(5))
        .danger_accept_invalid_certs(false)
        .build()
    {
        Ok(c) => c,
        Err(_) => {
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                "Failed to create HTTP client",
            )
                .into_response()
        }
    };

    match client.get(url.as_str()).send().await {
        Ok(response) => {
            let status = response.status();
            match response.bytes().await {
                Ok(body) => (status, body.to_vec()).into_response(),
                Err(_) => (
                    StatusCode::INTERNAL_SERVER_ERROR,
                    "Failed to read response body",
                )
                    .into_response(),
            }
        }
        Err(_) => (StatusCode::BAD_GATEWAY, "Failed to fetch URL").into_response(),
    }
}

